### Step 4: Create client/src/components/VisitorForm.js
```javascript
import React, { useState } from 'react';

export default function VisitorForm({ apiUrl, onVisitorAdded }) {
  const [formData, setFormData] = useState({
    name: '',
    company: '',
    phone_number: '',
    coming_from: '',
    to_meet: '',
    scheduled: false,
    purpose: '',
    location: ''
  });

  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');
    setLoading(true);

    try {
      const response = await fetch(`${apiUrl}/visitor`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(formData)
      });

      if (!response.ok) {
        throw new Error('Failed to add visitor');
      }

      const data = await response.json();
      setMessage(data.message);

      setFormData({
        name: '',
        company: '',
        phone_number: '',
        coming_from: '',
        to_meet: '',
        scheduled: false,
        purpose: '',
        location: ''
      });

      if (onVisitorAdded) {
        onVisitorAdded();
      }

      setTimeout(() => setMessage(''), 3000);
    } catch (err) {
      setError(err.message || 'An error occurred');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="form-container">
      <h2>Add Visitor</h2>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}

      <form onSubmit={handleSubmit}>
        <div className="form-row">
          <div className="form-group">
            <label>Name *</label>
            <input
              type="text"
              name="name"
              value={formData.name}
              onChange={handleChange}
              required
            />
          </div>
          <div className="form-group">
            <label>Company</label>
            <input
              type="text"
              name="company"
              value={formData.company}
              onChange={handleChange}
            />
          </div>
        </div>

        <div className="form-row">
          <div className="form-group">
            <label>Phone Number</label>
            <input
              type="tel"
              name="phone_number"
              value={formData.phone_number}
              onChange={handleChange}
            />
          </div>
          <div className="form-group">
            <label>Coming From</label>
            <input
              type="text"
              name="coming_from"
              value={formData.coming_from}
              onChange={handleChange}
            />
          </div>
        </div>

        <div className="form-row">
          <div className="form-group">
            <label>To Meet</label>
            <input
              type="text"
              name="to_meet"
              value={formData.to_meet}
              onChange={handleChange}
            />
          </div>
          <div className="form-group">
            <label>Location</label>
            <input
              type="text"
              name="location"
              value={formData.location}
              onChange={handleChange}
            />
          </div>
        </div>

        <div className="form-group">
          <label>Purpose</label>
          <textarea
            name="purpose"
            value={formData.purpose}
            onChange={handleChange}
            rows="3"
          ></textarea>
        </div>

        <div className="form-group checkbox-group">
          <input
            type="checkbox"
            name="scheduled"
            checked={formData.scheduled}
            onChange={handleChange}
          />
          <label style={{ margin: 0 }}>Scheduled Visit</label>
        </div>

        <button type="submit" className="submit-btn" disabled={loading}>
          {loading ? 'Adding...' : 'Add Visitor'}
        </button>
      </form>
    </div>
  );
}
```

