import React, { useState } from 'react';

export default function ConsignmentForm({ apiUrl, onConsignmentAdded }) {
  const [formData, setFormData] = useState({
    type: 'INWARD',
    document_number: '',
    document_type: '',
    vehicle_number: '',
    driver_contact: '',
    qty: '',
    package_type: '',
    comment: '',
    security_name: '',
    location: ''
  });

  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');
    setLoading(true);

    try {
      const response = await fetch(`${apiUrl}/consignment`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          ...formData,
          qty: formData.qty ? parseInt(formData.qty) : null
        })
      });

      if (!response.ok) {
        throw new Error('Failed to add consignment');
      }

      const data = await response.json();
      setMessage(data.message);

      setFormData({
        type: 'INWARD',
        document_number: '',
        document_type: '',
        vehicle_number: '',
        driver_contact: '',
        qty: '',
        package_type: '',
        comment: '',
        security_name: '',
        location: ''
      });

      if (onConsignmentAdded) {
        onConsignmentAdded();
      }

      setTimeout(() => setMessage(''), 3000);
    } catch (err) {
      setError(err.message || 'An error occurred');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="form-container">
      <h2>Add Consignment</h2>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}

