import React, { useState } from 'react';

export default function VisitorForm({ apiUrl, onVisitorAdded }) {
  const [formData, setFormData] = useState({
    name: '',
    company: '',
    phone_number: '',
    coming_from: '',
    to_meet: '',
    scheduled: false,
    purpose: '',
    location: ''
