+### Step 4: Create client/src/components/VisitorForm.js
+```javascript
+import React, { useState } from 'react';
+
+export default function VisitorForm({ apiUrl, onVisitorAdded }) {
+  const [formData, setFormData] = useState({
+    name: '',
+    company: '',
+    phone_number: '',
+    coming_from: '',
