import React, { useState, useEffect } from 'react';

export default function VisitorList({ apiUrl, refresh }) {
  const [visitors, setVisitors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchVisitors();
  }, [refresh, apiUrl]);

  const fetchVisitors = async () => {
    try {
      setLoading(true);
      setError('');
      const response = await fetch(`${apiUrl}/visitors`);

      if (!response.ok) {
        throw new Error('Failed to fetch visitors');
      }

      const data = await response.json();
      setVisitors(data);
    } catch (err) {
      setError(`✗ ${err.message}`);
      console.error('Error fetching visitors:', err);
    } finally {
      setLoading(false);
    }
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit'
    });
  };

  if (loading) return <div className="loading">Loading visitors...</div>;
  if (error) return <div className="error-message">{error}</div>;

  return (
    <div className="list-container">
      <h2>Visitors List ({visitors.length})</h2>
      {visitors.length === 0 ? (
        <div className="no-data">No visitors found. Add one to get started!</div>
      ) : (
        <div className="table-container">
          <table>
            <thead>
              <tr>
                <th>ID</th>
                <th>Name</th>
                <th>Company</th>
                <th>Phone</th>
                <th>From</th>
                <th>To Meet</th>
                <th>Purpose</th>
                <th>Location</th>
                <th>Check-in</th>
                <th>Scheduled</th>
              </tr>
            </thead>
            <tbody>
              {visitors.map(visitor => (
                <tr key={visitor.id}>
                  <td>{visitor.id}</td>
                  <td><strong>{visitor.name}</strong></td>
                  <td>{visitor.company || '-'}</td>
                  <td>{visitor.phone_number || '-'}</td>
                  <td>{visitor.coming_from || '-'}</td>
                  <td>{visitor.to_meet || '-'}</td>
                  <td>{visitor.purpose || '-'}</td>
                  <td>{visitor.location || '-'}</td>
                  <td>{formatDate(visitor.checkin)}</td>
                  <td>{visitor.scheduled ? '✓ Yes' : 'No'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
      <button 
        onClick={fetchVisitors} 
        style={{ marginTop: '20px', padding: '8px 16px', cursor: 'pointer' }}
      >
        Refresh
      </button>
    </div>
  );
}

