import React, { useState } from 'react';

export default function ConsignmentForm({ apiUrl, onConsignmentAdded }) {
  const [formData, setFormData] = useState({
    type: 'INWARD',
    document_number: '',
    document_type: '',
    vehicle_number: '',
    driver_contact: '',
    qty: '',
    package_type: '',
    comment: '',
    security_name: '',
    location: ''
  });

  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');
    setLoading(true);

    try {
      const response = await fetch(`${apiUrl}/consignment`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          ...formData,
          qty: formData.qty ? parseInt(formData.qty) : null
        })
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to add consignment');
      }

      const data = await response.json();
      setMessage(`✓ ${data.message}`);

      // Reset form
      setFormData({
        type: 'INWARD',
        document_number: '',
        document_type: '',
        vehicle_number: '',
        driver_contact: '',
        qty: '',
        package_type: '',
        comment: '',
        security_name: '',
        location: ''
      });

      // Notify parent to refresh list
      if (onConsignmentAdded) {
