export default function ConsignmentList({ apiUrl, refresh }) {
  const [consignments, setConsignments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [filter, setFilter] = useState('ALL');

  useEffect(() => {
    fetchConsignments();
  }, [refresh, apiUrl]);

  const fetchConsignments = async () => {
    try {
      setLoading(true);
      setError('');
      const response = await fetch(`${apiUrl}/consignments`);

      if (!response.ok) {
        throw new Error('Failed to fetch consignments');
      }

      const data = await response.json();
      setConsignments(data);
    } catch (err) {
      setError(`✗ ${err.message}`);
      console.error('Error fetching consignments:', err);
    } finally {
      setLoading(false);
    }
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit'
    });
  };

  const filteredConsignments = consignments.filter(c => 
    filter === 'ALL' ? true : c.type === filter
  );

  if (loading) return <div className="loading">Loading consignments...</div>;
  if (error) return <div className="error-message">{error}</div>;

  return (
    <div className="list-container">
      <h2>Consignments List ({filteredConsignments.length})</h2>

      <div style={{ marginBottom: '20px' }}>
        <label style={{ marginRight: '10px' }}>Filter by Type:</label>
        <select 
          value={filter} 
          onChange={(e) => setFilter(e.target.value)}
          style={{ padding: '8px', borderRadius: '5px', border: '1px solid #ddd' }}
        >
          <option value="ALL">All Types</option>
          <option value="INWARD">INWARD Only</option>
          <option value="OUTWARD">OUTWARD Only</option>
        </select>
      </div>

      {filteredConsignments.length === 0 ? (
        <div className="no-data">No consignments found.</div>
      ) : (
        <div className="table-container">
          <table>
            <thead>
              <tr>
                <th>ID</th>
                <th>Type</th>
                <th>Document #</th>
                <th>Document Type</th>
                <th>Vehicle #</th>
                <th>Driver</th>
                <th>Qty</th>
                <th>Package</th>
                <th>Security</th>
                <th>Location</th>
                <th>Time</th>
                <th>Comment</th>
              </tr>
            </thead>
            <tbody>
              {filteredConsignments.map(consignment => (
                <tr key={consignment.id}>
                  <td>{consignment.id}</td>
                  <td>
                    <strong 
                      style={{
                        color: consignment.type === 'INWARD' ? '#28a745' : '#dc3545'
                      }}
                    >
                      {consignment.type}
                    </strong>
                  </td>
                  <td>{consignment.document_number || '-'}</td>
                  <td>{consignment.document_type || '-'}</td>
                  <td>{consignment.vehicle_number || '-'}</td>
                  <td>{consignment.driver_contact || '-'}</td>
                  <td>{consignment.qty || '-'}</td>
                  <td>{consignment.package_type || '-'}</td>
                  <td>{consignment.security_name || '-'}</td>
                  <td>{consignment.location || '-'}</td>
                  <td>{formatDate(consignment.in_time)}</td>
                  <td>{consignment.comment ? consignment.comment.substring(0, 20) + '...' : '-'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
      <button 
        onClick={fetchConsignments} 
        style={{ marginTop: '20px', padding: '8px 16px', cursor: 'pointer' }}
      >
        Refresh
      </button>
    </div>
  );
}

